// Lightweight shim to load AlpineJS when pages expect /static/js/cdn.min.js
(function(){
  try{
    var s = document.createElement('script');
    s.src = 'https://unpkg.com/alpinejs@3.x.x/dist/cdn.min.js';
    s.defer = true;
    s.crossOrigin = 'anonymous';
    document.head.appendChild(s);
  }catch(e){
    console && console.error && console.error('cdn.min.js loader error', e);
  }
})();
